gVh(){return"\u0626\u06d5\u067e\u06cc \u0639\u0648\u0645\u0631\u06d5 \u0628\u0627\u0632\u0627\u0695\u06ce\u06a9\u06d5 \u06a9\u06d5 \u06af\u06d5\u0634\u062a\u06cc\u0627\u0631\u0627\u0646 \u0628\u06d5 \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627 \u06af\u06d5\u0634\u062a\u06cc\u06cc\u06d5 \u0645\u06c6\u06b5\u06d5\u062a\u062f\u0627\u0631\u06d5\u06a9\u0627\u0646\u06d5\u0648\u06d5 \u062f\u06d5\u0628\u06d5\u0633\u062a\u06ce\u062a\u06d5\u0648\u06d5. \u062d\u062c\u0632\u06d5\u06a9\u0627\u0646 \u0644\u06d5 \u0695\u06ce\u06af\u06d5\u06cc \u0626\u06d5\u067e\u06d5\u06a9\u06d5\u0648\u06d5 \u062f\u0627\u0648\u0627\u06a9\u0627\u0631\u06cc\u0646: \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627\u06a9\u06d5 \u067e\u0634\u062a\u0695\u0627\u0633\u062a\u06cc\u0627\u0646 \u062f\u06d5\u06a9\u0627\u062a\u06d5\u0648\u06d5 \u06cc\u0627\u0646 \u0695\u06d5\u062a\u06cc\u0627\u0646 \u062f\u06d5\u06a9\u0627\u062a\u06d5\u0648\u06d5\u060c \u0648 \u067e\u0627\u0631\u06d5\u062f\u0627\u0646 \u0695\u0627\u0633\u062a\u06d5\u0648\u062e\u06c6 \u0644\u0627\u06cc \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627\u06a9\u06d5 \u062f\u06d5\u0628\u06ce\u062a. \u0648\u0631\u062f\u06d5\u06a9\u0627\u0631\u06cc \u06af\u06d5\u0634\u062a \u0648 \u0646\u0631\u062e \u0648 \u0628\u06d5\u0631\u062f\u06d5\u0633\u062a\u0628\u0648\u0648\u0646 \u0644\u06d5\u0644\u0627\u06cc\u06d5\u0646 \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627\u06a9\u0627\u0646\u06d5\u0648\u06d5 \u062f\u0627\u0628\u06cc\u0646 \u062f\u06d5\u06a9\u0631\u06ce\u0646 \u0648 \u0644\u06d5\u0648\u0627\u0646\u06d5\u06cc\u06d5 \u0628\u06af\u06c6\u0695\u06ce\u0646.\n\n\u0628\u06d5 \u0628\u06d5\u06a9\u0627\u0631\u0647\u06ce\u0646\u0627\u0646\u06cc \u0626\u06d5\u067e\u06d5\u06a9\u06d5 \u0695\u0627\u0632\u06cc \u062f\u06d5\u0628\u06cc\u062a \u0628\u06d5 \u067e\u06ce\u062f\u0627\u0646\u06cc \u0632\u0627\u0646\u06cc\u0627\u0631\u06cc \u062f\u0631\u0648\u0633\u062a \u0648 \u0628\u06d5\u06a9\u0627\u0631\u0647\u06ce\u0646\u0627\u0646\u06cc \u062e\u0632\u0645\u06d5\u062a\u06af\u0648\u0632\u0627\u0631\u06cc\u06cc\u06d5\u06a9\u06d5 \u062a\u06d5\u0646\u0647\u0627 \u0628\u06c6 \u0645\u06d5\u0628\u06d5\u0633\u062a\u06cc \u06a9\u06d5\u0633\u06cc \u0648 \u06cc\u0627\u0633\u0627\u06cc\u06cc. \u0626\u06d5\u067e\u06d5\u06a9\u06d5 \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627\u06cc \u06af\u06d5\u0634\u062a \u0646\u06cc\u06cc\u06d5 \u0648 \u0644\u0627\u06cc\u06d5\u0646\u06ce\u06a9 \u0646\u06cc\u06cc\u06d5 \u0644\u06d5 \u06af\u0631\u06ce\u0628\u06d5\u0633\u062a\u06cc \u0646\u06ce\u0648\u0627\u0646 \u062a\u06c6 \u0648 \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627\u06a9\u06d5."},
